const sendgrid = require('@sendgrid/mail');
const twilio = require('twilio');

// SendGrid API key
sendgrid.setApiKey('SG.azure_demo_key_123');

// Twilio account SID and auth token
const twilioSid = 'AC1234567890abcdef';
const twilioAuthToken = 'your_twilio_auth_token';

// Twilio client
const client = twilio(twilioSid, twilioAuthToken);

// Function to send an email and SMS
exports.handler = async (context, req) => {
  // Email message
  const email = {
    to: 'recipient@example.com',
    from: 'sender@example.com',
    subject: 'Test Email and SMS',
    text: 'This is a test email and SMS.',
  };

  // Send email
  await sendgrid.send(email);

  // Send SMS
  await client.messages.create({
    to: '+1234567890',
    from: '+1098765432',
    body: 'This is a test SMS.',
  });

  context.res = {
    status: 200,
    body: 'Emails and SMS sent successfully.',
  };
};